import base64

NEW_BANNER_BLOCK_B64 = ""
SLIDER_CONTENT_B64 = ""

# --- 1. Patch App.tsx: replace category banner block between markers ---
with open("src/App.tsx", "r", encoding="utf-8") as f:
    content = f.read()

start_marker = "{/* \U0001F697 vs \u2699\uFE0F Side-by-Side Main Category Buy/Sell Buttons */}"
end_marker = "{/* \U0001F6E0\uFE0F Modern Filters & Dynamic Sorting Panel (Revealed dynamically!) */}"

start_idx = content.find(start_marker)
end_idx = content.find(end_marker)

if start_idx == -1 or end_idx == -1:
    print("ERROR: markers not found in App.tsx, aborting App.tsx patch")
else:
    new_block = base64.b64decode(NEW_BANNER_BLOCK_B64).decode("utf-8")
    before = content[:start_idx + len(start_marker)]
    after = content[end_idx:]
    content = before + "\n" + new_block + "\n                " + after
    with open("src/App.tsx", "w", encoding="utf-8") as f:
        f.write(content)
    print("OK: App.tsx category banners updated")

# --- 2. Overwrite PromotedSlider.tsx entirely ---
slider_content = base64.b64decode(SLIDER_CONTENT_B64).decode("utf-8")
with open("src/components/PromotedSlider.tsx", "w", encoding="utf-8") as f:
    f.write(slider_content)
print("OK: PromotedSlider.tsx replaced with Boost Ads design")
